import streamlit as stfrom bridge import MGEPlusBridge# Page configst.set_page_config(page_title="INTENTICS", layout="wide")st.markdown("""<style>div.stButton > button {    background-color: #d4f5d0;    color: black;    border-radius: 8px;    border: 1px solid #000000;    font-weight: 600;}div.stButton > button:hover {    background-color: #c6efc1;}</style>""", unsafe_allow_html=True)# Titlesst.image("intentics_logo.png", width=220)st.title("🟢 Intentics powered by TEF")st.caption("**See how aligned you are - and what it would take to close the gap.**")# Two-column layoutcol1, col2 = st.columns(2)with col1:    st.markdown("### Founder Testimony")    founder_text = st.text_area(        "Founder",        placeholder="Paste founder testimony here...",        height=200    )with col2:    st.markdown("### Investor Testimony")    investor_text = st.text_area(        "Investor",        placeholder="Paste investor testimony here...",        height=200    )# Initialize systembridge = MGEPlusBridge()# Buttonif st.button("Show Alignment"):        result = bridge.run_dual_analysis(founder_text, investor_text)    # Empty input check    if result.get("score", 0) == 0 and (not founder_text.strip() or not investor_text.strip()):        st.warning("Please provide both testimonies.")    else:        st.success(f"Shared Coherence Score: {result['score']}%")        st.markdown("### Alignment Gap")        st.info(result["gap"])        st.markdown("### Founder Adjustment")        st.write(result["founder_adjustment"])        st.markdown("### Investor Adjustment")        st.write(result["investor_adjustment"])        st.markdown("### Projected Improved Coherence")        st.metric("Projected", f"{result['improved_score']}%")# Footerst.caption("Intentics • Powered by TEF • Real Alignment Intelligence")